const amqplib = require('amqplib');

async function main() {
  try {
    const connection = await amqplib.connect('amqp://localhost');
    const channel = await connection.createChannel();

    // Declare queue if it doesn't exist
    await channel.assertQueue('my_queue', { durable: true });

    console.log('Waiting for messages in my_queue...');

    channel.consume('my_queue', (msg) => {
      if (msg !== null) {
        const message = JSON.parse(msg.content.toString());
        switch (message.type) {
          case 'CREATE_USER':
            createUser(message.payload);
            break;
          case 'UPDATE_USER':
            updateUser(message.payload);
            break;
          default:
            console.log(`Unknown message type: ${message.type}`);
        }
      }
    }, { noAck: true });

    process.on('SIGINT', () => {
      channel.cancel();
      connection.close();
    });
  } catch (err) {
    console.error(err);
  }
}

async function createUser(payload) {
  const db = require('./db'); // assuming a database module
  try {
    await db.query(`INSERT INTO users SET ?`, payload);
    console.log('User created successfully');
  } catch (err) {
    console.error(err);
  }
}

async function updateUser(payload) {
  const db = require('./db'); // assuming a database module
  try {
    await db.query(`UPDATE users SET ? WHERE id = ?`, [payload, payload.id]);
    console.log('User updated successfully');
  } catch (err) {
    console.error(err);
  }
}

